const { ethers } = require('ethers');
require('dotenv').config();

// Load environment variables
const INFURA_PROJECT_ID = process.env.INFURA_PROJECT_ID;
const PRIVATE_KEY = process.env.PRIVATE_KEY;

// Validate environment variables
if (!INFURA_PROJECT_ID || !PRIVATE_KEY) {
  throw new Error('Environment variables INFURA_PROJECT_ID and PRIVATE_KEY must be set');
}

// Connect to Ethereum network
const provider = new ethers.providers.InfuraProvider('mainnet', INFURA_PROJECT_ID);

// Create wallet instance
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

// Function to send ETH
async function sendETH(toAddress, amountInEther) {
  if (!ethers.utils.isAddress(toAddress)) {
    throw new Error('Invalid Ethereum address');
  }

  const tx = {
    to: toAddress,
    value: ethers.utils.parseEther(amountInEther),
  };

  try {
    const transactionResponse = await wallet.sendTransaction(tx);
    await transactionResponse.wait();
    console.log(`Transaction successful with hash: ${transactionResponse.hash}`);
  } catch (error) {
    console.error('Transaction failed:', error);
  }
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, functionName, ...args) {
  if (!ethers.utils.isAddress(contractAddress)) {
    throw new Error('Invalid contract address');
  }

  const contract = new ethers.Contract(contractAddress, abi, wallet);

  try {
    const response = await contract[functionName](...args);
    await response.wait();
    console.log(`Contract interaction successful with hash: ${response.hash}`);
  } catch (error) {
    console.error('Contract interaction failed:', error);
  }
}

